/// exclusively in [`Context::sort_descriptor`] per spec §1.1.1.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub enum State {
    /// The table is at rest.
    #[default]
    Idle,
}

// ────────────────────────────────────────────────────────────────────
