    SetRows(Vec<Key>),

    /// Replace [`Context::dir`]. Idempotent.
    SetDirection(Direction),

    /// Replace the virtualized total row / column counts (§3.5).
    SetRowCounts {
        /// Total row count across the entire dataset.
