/// Trend direction for the Stat component.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum Trend {
    /// The value is increasing.
    Up,

    /// The value is decreasing.
    Down,

    /// The value is neutral.
    Neutral,
}

impl Trend {
    /// Returns the `data-ars-trend` value for this trend.
