    AnnounceRemoved,
}

/// Structural parts exposed by the TagGroup connect API.
#[derive(Clone, Debug, ComponentPart)]
#[scope = "tag-group"]
pub enum Part {
    /// The root tag group element.
    Root,

    /// The visible label element.
    Label,

    /// The wrapper row containing tags.
