    assert_eq!(api.item_attrs(1).get(&HtmlAttr::TabIndex), Some("0"));

    api.on_control_keydown(&keyboard(KeyboardKey::ArrowRight));
    api.on_control_keydown(&keyboard(KeyboardKey::ArrowLeft));
