            rating_group::Event::Focus {
                index: 3,
                is_keyboard: true,
            },
            rating_group::Event::Blur,
            rating_group::Event::HoverItem(4),
            rating_group::Event::UnHover,
            rating_group::Event::Rate(3.0),
